import React, { useState } from "react";


function ModelAccuracy() {

  const data = {
    best_model: "XGBoost",
    best_accuracy: 93.4,
    all_models: {
      "Linear Regression": 82.5,
      "Random Forest": 91.2,
      "Decision Tree": 87.6,
      "XGBoost": 93.4
    }
  };

  const [show, setShow] = useState(false);

  return (
    <div>

      {/* Best Model */}
      <div onClick={() => setShow(true)}>
        <h2>{data.best_model}</h2>
        <h1>{data.best_accuracy}%</h1>
      </div>

      {/* Popup */}
      {show && (
        <div>
          <h2>All Models</h2>

          {Object.entries(data.all_models).map(([model, acc]) => (
            <p key={model}>{model} - {acc}%</p>
          ))}

          <button onClick={() => setShow(false)}>Close</button>
        </div>
      )}

    </div>
  );
}

export default ModelAccuracy;
